-- CITY / PROVINCE (5 rows)
INSERT INTO city (name, country, code)
SELECT v.name, v.country, v.code FROM (VALUES
  'East', 'Rwanda', 'EAS',
  'Kigali', 'Rwanda', 'KIG',
  'North', 'Rwanda', 'NOR',
  'South', 'Rwanda', 'SOU',
  'West', 'Rwanda', 'WES'
) AS v(name, country, code)
WHERE NOT EXISTS (SELECT 1 FROM city WHERE name = v.name);

