JOIN district d  ON d.name  = v.district_name AND d.city_id    = ci.id
JOIN sector       s  ON s.name  = v.sector_name   AND s.district_id = d.id
JOIN cell         ce ON ce.name = v.cell_name      AND ce.sector_id  = s.id
ON CONFLICT (name, cell_id) DO NOTHING;

