  ('Kamabuye', 'Mushaka', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-MUS-V04'),
  ('Nyagashora', 'Mushaka', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-MUS-V05'),
  ('Gatare', 'Rubugu', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUB-V01'),
  ('Ntenyi', 'Rubugu', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUB-V02'),
  ('Nyange', 'Rubugu', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUB-V03'),
  ('Rukombe', 'Rubugu', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUB-V04'),
  ('Cyunguriro', 'Ruganda', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUG-V01'),
  ('Musumba', 'Ruganda', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUG-V02'),
  ('Rubamba', 'Ruganda', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUG-V03'),
  ('Rubuye', 'Ruganda', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUG-V04'),
  ('Ruhinga', 'Ruganda', 'Rwimbogo', 'Rusizi', 'West', 'WES-RUS-RWI-RUG-V05')
) AS v(name, cell_name, sector_name, district_name, city_name, code)
JOIN city         ci ON ci.name = v.city_name
JOIN district d  ON d.name  = v.district_name AND d.city_id    = ci.id
JOIN sector       s  ON s.name  = v.sector_name   AND s.district_id = d.id
JOIN cell         ce ON ce.name = v.cell_name      AND ce.sector_id  = s.id
ON CONFLICT (name, cell_id) DO NOTHING;
